let user = { name: "Geralt" };

const weakMap = new WeakMap();
weakMap.set(user, "secret data");

const map = new Map();
map.set(user, "secret data");

console.log(weakMap.get(user)); // "secret data"
console.log(map.get(user)); // "secret data"

user = null;

// WeakMap:
// the object can be garbage collected, so the entry may disappear automatically.

// Map:
// the entry stays in the map, because Map keeps a strong reference to the key.

console.log(map.size); // 1

